let passed = 0, failed = 0;
function ok(label, cond) { if (cond) { passed++; console.log('  ✓', label); } else { failed++; console.log('  ✗', label); } }

function req(method, url, body) {
  return new Promise((resolve, reject) => {
    const opts = { hostname: '127.0.0.1', port: PORT, path: url, method, headers: {} };
    if (body) {
      const buf = Buffer.from(body, 'utf-8');
      opts.headers['Content-Type'] = 'application/json';
      opts.headers['Content-Length'] = buf.length;
    }
    const r = http.request(opts, (res) => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => { try { resolve(JSON.parse(d)); } catch { resolve(d); } });
    });
    r.on('error', reject);
    if (body) r.write(body);
    r.end();
  });
}

(async () => {
  await new Promise(r => setTimeout(r, 1200));

  try {
    console.log('\n=== Test 1: POST /api/select then GET /api/wait ===');
    const p1 = await req('POST', '/api/select', JSON.stringify({choice:'A',text:'Option A',feedback:'Works'}));
    ok('POST returns ok', p1.ok === true);
    const w1 = await req('GET', '/api/wait', null);
    ok('wait returns choice A', w1.choice === 'A');
    ok('wait returns feedback', w1.feedback === 'Works');

    console.log('\n=== Test 2: New screen resets decision ===');
    fs.writeFileSync(path.join(SCREEN_DIR, 's2.html'), '<h1>Screen 2</h1>');
    await new Promise(r => setTimeout(r, 500));
    const w2p = req('GET', '/api/wait', null);
    await new Promise(r => setTimeout(r, 200));
    const p2 = await req('POST', '/api/select', JSON.stringify({choice:'B',feedback:'Screen 2'}));
