    const w3p = req('GET', '/api/wait', null);
    const timeout = new Promise(r => setTimeout(() => r({_timeout:true}), 1500));
    const w3 = await Promise.race([w3p, timeout]);
    ok('wait blocks (no selection)', w3._timeout === true);

    console.log(`\n=== ${passed} passed, ${failed} failed ===`);
