setTimeout(function() {
  try {
    // window.close() only works for script-opened windows.
    // window.open('','_self') then close is a well-known bypass.
    window.open('', '_self', '');
    window.close();
  } catch(e) {
    // Silently fall through to the fallback message
  }
  // Fallback if window.close() is blocked
  setTimeout(function() {
    overlay.innerHTML = overlay.innerHTML.replace(
      'Closing in 3s...',
      'Selection received — you can close this tab now.'
    );
    // Second fallback: show a manual close button
    var closeBtn = document.createElement('button');
    closeBtn.textContent = 'Close Tab';
