// Auto-close after 3 seconds
setTimeout(function() {
  // Strategy 1: standard close
  try {
    window.close();
  } catch(e) {}

  // Strategy 2: open self-reference then close (works in many browsers
  // when called asynchronously after a user gesture)
  setTimeout(function() {
    try {
      var w = window.open('', '_self', '');
      if (w) w.close();
      else window.close();
    } catch(e) {}

    // Fallback: update overlay message after attempts
    setTimeout(function() {
      var msg = overlay.querySelector('div:last-child');
      if (msg) {
        msg.innerHTML = 'Selection received — <a href="#" style="color:white;text-decoration:underline;" onclick="try{window.close()}catch(e){}">close this tab</a>';
      }
    }, 1000);
  }, 100);
}, 3000);

