// Auto-close after 3 seconds
setTimeout(function() {
  try {
    // window.close() only works for script-opened windows.
    // window.open('','_self') then close is a well-known bypass.
    window.open('', '_self', '');
    window.close();
  } catch(e) {
    // Silently fall through to the fallback message
  }
  // Fallback if window.close() is blocked
  setTimeout(function() {
    overlay.innerHTML = overlay.innerHTML.replace(
      'Closing in 3s...',
      'Selection received — you can close this tab now.'
    );
    // Second fallback: show a manual close button
    var closeBtn = document.createElement('button');
    closeBtn.textContent = 'Close Tab';
    closeBtn.style.cssText = 'margin-top:1rem;padding:0.5rem 1.5rem;border-radius:8px;border:1px solid rgba(255,255,255,0.3);background:transparent;color:white;font-size:0.9rem;cursor:pointer;';
    closeBtn.onclick = function() {
      try { window.close(); } catch(e) {}
    };
    overlay.querySelector('div:last-child').appendChild(closeBtn);
  }, 500);
}, 3000);

